// registry.ts — allowlist of components the model may request
import { lazy } from "react";

// Only components explicitly added here can be rendered from model output.
// React.lazy ensures each component is code-split and loaded on demand.
export const COMPONENT_REGISTRY: Record<string, React.LazyExoticComponent<any>> = {
  MetricCard:      lazy(() => import("./components/MetricCard")),
  LineChart:       lazy(() => import("./components/LineChart")),
  DataTable:       lazy(() => import("./components/DataTable")),
  DashboardLayout: lazy(() => import("./components/DashboardLayout")),
  PieChart:        lazy(() => import("./components/PieChart")),
  CalendarView:    lazy(() => import("./components/CalendarView")),
};

export type RegisteredComponentName = keyof typeof COMPONENT_REGISTRY;

// componentSchema.ts — JSON Schema for model-generated component trees
export interface ComponentSpec {
  type:      string;               // must match a key in COMPONENT_REGISTRY
  props?:    Record<string, unknown>;
  children?: ComponentSpec[];      // nested components (max depth: 3)
}

// Zod schema for runtime validation
import { z } from "zod";

const ComponentSpecSchema: z.ZodType<ComponentSpec> = z.lazy(() =>
  z.object({
    type:     z.string().max(64),
    props:    z.record(z.unknown()).optional(),
    children: z.array(ComponentSpecSchema).max(12).optional(),
  })
);

export function validateComponentSpec(raw: unknown): ComponentSpec {
  // This throws ZodError on invalid input
  return ComponentSpecSchema.parse(raw);
}

// Tool schema sent to the model:
export const RENDER_DASHBOARD_TOOL = {
  name: "render_dashboard",
  description: "Render a dynamic dashboard layout with metric cards, charts, and tables.",
  input_schema: {
    type: "object",
    properties: {
      layout: {
        type: "object",
        properties: {
          type:     { type: "string", enum: Object.keys(COMPONENT_REGISTRY) },
          props:    { type: "object" },
          children: {
            type:  "array",
            items: {
              type: "object",
              properties: {
                type:  { type: "string", enum: Object.keys(COMPONENT_REGISTRY) },
                props: { type: "object" },
              },
              required: ["type"],
            },
            maxItems: 8,
          },
        },
        required: ["type"],
      },
    },
    required: ["layout"],
  },
};

// DynamicRenderer.tsx — renders a ComponentSpec tree safely
import { Suspense, Component, type ReactNode } from "react";
import { COMPONENT_REGISTRY }     from "./registry";
import { validateComponentSpec }  from "./componentSchema";
import type { ComponentSpec }     from "./componentSchema";

const MAX_DEPTH = 3;

// Error boundary — shows fallback if a lazy component throws
class ComponentErrorBoundary extends Component<
  { children: ReactNode; name: string },
  { error: Error | null }
> {
  state = { error: null };
  static getDerivedStateFromError(error: Error) { return { error }; }

  render() {
    if (this.state.error) {
      return (
        <div className="rounded-lg border border-red-800 bg-red-950 p-3 text-xs text-red-400">
          Component "{this.props.name}" failed to render.
        </div>
      );
    }
    return this.props.children;
  }
}

interface DynamicRendererProps {
  spec:    unknown;   // raw model output — validated inside
  depth?:  number;
}

export function DynamicRenderer({ spec, depth = 0 }: DynamicRendererProps) {
  // 1. Enforce depth limit (prevent infinite recursion via model-generated trees)
  if (depth > MAX_DEPTH) {
    return <p className="text-xs text-slate-500">[max depth reached]</p>;
  }

  // 2. Validate structure (throws on malformed input)
  let node: ComponentSpec;
  try {
    node = validateComponentSpec(spec);
  } catch {
    return (
      <pre className="text-xs text-slate-500 bg-slate-900 rounded p-2 overflow-x-auto">
        {JSON.stringify(spec, null, 2)}
      </pre>
    );
  }

  // 3. Look up in allowlist — never use eval or window[name]
  const LazyComponent = COMPONENT_REGISTRY[node.type];
  if (!LazyComponent) {
    return (
      <p className="text-xs text-slate-500">
        Unknown component: {node.type}
      </p>
    );
  }

  // 4. Render with error boundary + Suspense (lazy load)
  const children = node.children?.map((child, i) => (
    <DynamicRenderer key={i} spec={child} depth={depth + 1} />
  ));

  return (
    <ComponentErrorBoundary name={node.type}>
      <Suspense fallback={<ComponentSkeleton />}>
        <LazyComponent {...(node.props ?? {})}>{children}</LazyComponent>
      </Suspense>
    </ComponentErrorBoundary>
  );
}

function ComponentSkeleton() {
  return <div className="h-24 rounded-xl bg-slate-800 animate-pulse" />;
}

// propAllowlist.ts — per-component prop schemas to prevent injection
import { z } from "zod";

// Only primitive types in props — no functions, no JSX, no dangerouslySetInnerHTML
const safeValue = z.union([
  z.string().max(2000),
  z.number(),
  z.boolean(),
  z.null(),
  z.array(z.union([z.string(), z.number(), z.boolean()])).max(100),
]);

export const PROP_SCHEMAS: Record<string, z.ZodObject<any>> = {
  MetricCard: z.object({
    title:  z.string().max(100),
    value:  z.union([z.number(), z.string().max(50)]),
    unit:   z.string().max(20).optional(),
    trend:  z.enum(["up","down","flat"]).optional(),
    color:  z.enum(["blue","green","red","yellow","purple"]).optional(),
  }),
  LineChart: z.object({
    title:    z.string().max(100).optional(),
    data:     z.array(z.object({ x: safeValue, y: z.number() })).max(500),
    xLabel:   z.string().max(50).optional(),
    yLabel:   z.string().max(50).optional(),
  }),
  DataTable: z.object({
    title:   z.string().max(100).optional(),
    columns: z.array(z.object({ key: z.string(), label: z.string() })).max(20),
    rows:    z.array(z.record(safeValue)).max(200),
  }),
};

export function validateProps(componentType: string, rawProps: unknown): Record<string, unknown> {
  const schema = PROP_SCHEMAS[componentType];
  if (!schema) return {};   // unknown component — reject all props
  return schema.parse(rawProps);
}

// DynamicRenderer.test.tsx
import { render, screen } from "@testing-library/react";
import { DynamicRenderer } from "./DynamicRenderer";
import { vi }              from "vitest";

// Mock lazy components so tests don't need the full build
vi.mock("./registry", () => ({
  COMPONENT_REGISTRY: {
    MetricCard: ({ title, value }: { title: string; value: number }) => (
      <div data-testid="metric-card">{title}: {value}</div>
    ),
  },
}));

test("renders a valid MetricCard spec", () => {
  render(
    <DynamicRenderer spec={{ type: "MetricCard", props: { title: "Revenue", value: 1234 } }} />
  );
  expect(screen.getByTestId("metric-card")).toHaveTextContent("Revenue: 1234");
});

test("shows fallback for unknown component", () => {
  render(<DynamicRenderer spec={{ type: "UnknownWidget", props: {} }} />);
  expect(screen.getByText(/Unknown component: UnknownWidget/)).toBeInTheDocument();
});

test("enforces max depth", () => {
  // Tree nested deeper than MAX_DEPTH
  const deep = { type: "MetricCard", props: {}, children: [
    { type: "MetricCard", props: {}, children: [
      { type: "MetricCard", props: {}, children: [
        { type: "MetricCard", props: {} }   // depth 4 — should be truncated
      ]}
    ]}
  ]};
  render(<DynamicRenderer spec={deep} />);
  expect(screen.getByText(/max depth reached/)).toBeInTheDocument();
});

test("rejects malformed spec", () => {
  render(<DynamicRenderer spec={{ notAValidField: true }} />);
  // Falls back to JSON pretty-print
  expect(screen.getByText(/"notAValidField"/)).toBeInTheDocument();
});
